import{_ as a,o,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"44. On Call Recall","description":"","frontmatter":{"title":"44. On Call Recall","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","on-call","allowances"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/allowances/44-on-call-recall.md","filePath":"ebas/has-managers-admin/common-terms/allowances/44-on-call-recall.md"}'),l={name:"ebas/has-managers-admin/common-terms/allowances/44-on-call-recall.md"};function n(s,e,i,h,d,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_44-on-call-recall" tabindex="-1">44. On Call Recall <a class="header-anchor" href="#_44-on-call-recall" aria-label="Permalink to &quot;44. On Call Recall&quot;">​</a></h1><p><strong>44.1</strong> The Employer will pay an on call allowance to Employees who are required to be on call.</p><p><strong>44.2</strong> Where an Employee is recalled to duty during an off-duty period they will be paid a minimum of three hours at the appropriate rate.</p><p><strong>44.3</strong> Recall – Health and Allied Services Employees and Dental Assistants</p><p>The on call allowances in <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> will be paid to Health and Allied Services Employees and Dental Assistants as follows:</p><p><strong>(a)</strong> employees who are required to be on call, or who return to duty when off duty, will be paid an on call allowance in addition to any other amount payable, per twelve hours or part thereof. When recall work is necessary, it should be so arranged that Health and Allied Services Employees and Dental Assistants have at least 10 hours off duty between successive shifts.</p><p><strong>44.4</strong> Recall – Managers and Administrative Workers The on call allowances in <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a> will be paid to Managers and Administrative workers as follows:</p><p><strong>(a)</strong> the ‘On Call Allowance – Monday to Friday’ will be paid in respect of any 24-hour period or part thereof during which an Employee is on call during the period commencing from the time of finishing ordinary duty on Monday through until the termination of ordinary duty on Friday; and</p><p><strong>(b)</strong> the ‘On Call Allowance – Public Holidays and All other Times’ will be paid in respect of any other 24-hour period, or part thereof, or any public holiday, or part thereof, where the Employee is on call. When recall work is necessary, it should be so arranged that Managers and Administrative workers have at least 8 hours off duty between midnight and the commencement of the next period of ordinary duty.</p><p><strong>44.5</strong> Breaks between periods of work</p><p><strong>(a)</strong> An Employee who works so much overtime between the termination of their previous rostered shift and the commencement of their next rostered shift, that they would not have a 10-hour break will be released after completion of such recall worked until they have had a 10-hour break. The Employee will not suffer any loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>(b)</strong> If, on the instructions of the Employer, an Employee resumes or continues work without having had a 10-hour break they will be paid at the rate of 200% (based on 1/38th of the weekly salary set out in such rest period. The Employee will then be entitled to be absent until they have had a 10-hour break. The Employee will not suffer any loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>44.6</strong> Recall – Telephone Allowance Managers and Administrative Workers only Notwithstanding clause 44.2, where recall to duty can be managed without a Manager or Administrative Worker having to return to their workplace,</p><p>such as by telephone, such Employee will be paid a minimum of one hour’s overtime, provided that multiple recalls within a discrete hour will not attract additional payment.</p><p><strong>44.7</strong> Recall – Transport Allowance Health &amp; Allied Services Employees and Dental Assistants only Where a Health &amp; Allied Services Employee or Dental Assistant finishes a period of overtime at a time when reasonable means of transport are not available for them to return to their place of residence, the Employer will provide adequate transport free of charge.</p><p>Plain language terms: on-call, recall, called in, called back.</p>',16)])])}const u=a(l,[["render",n]]);export{m as __pageData,u as default};
